"use client";

import { useState } from "react";
import { C } from "@/components/shared/vibeTheme";
import { Divider, Orb, PricingCard, Reveal, Tag } from "@/components/shared/ui";
import { AD_PRICING, BIZ_PRICING, CREATOR_TIERS } from "@/components/data/pricing";

export default function PricingPage({openWaitlist}){
  const[activeProduct,setActiveProduct]=useState("Creators");
  const[annual,setAnnual]=useState(false);
  const products={
    Creators:{icon:"---",tiers:CREATOR_TIERS,tagline:"Plans for creators at every stage.",color:C.orange},
    Business:{icon:"----",tiers:BIZ_PRICING,tagline:"Plans for businesses of every size.",color:C.orange},
    Advertise:{icon:"----",tiers:AD_PRICING,tagline:"Plans for brands that mean business.",color:C.pink},
  };
  const current=products[activeProduct];
  const faqItems=[{q:"Can I switch plans at any time?",a:"Yes. Upgrade, downgrade, or cancel anytime from your account settings. Changes take effect at the start of your next billing period."},{q:"Is there a free trial?",a:"Creator Spark is free forever. Creator Pulse and all Business plans include a 14-day free trial. No credit card required to start."},{q:"What happens when my trial ends?",a:"You'll be prompted to add payment details. If you don't, your account automatically downgrades to the free Spark tier --- you never lose your data."},{q:"Do you offer annual billing?",a:"Yes. Annual billing saves 20% across all paid plans. Toggle above to see annual pricing."},{q:"Do you offer nonprofit or student discounts?",a:"Yes. Verified nonprofits and enrolled students get 50% off Creator Pulse. Email info@vibecircle.com with proof of status."}];
  return(
    <div style={{background:C.bg,color:C.white}}>
      <section style={{minHeight:"42vh",display:"flex",flexDirection:"column",justifyContent:"flex-end",padding:"130px 64px 72px",position:"relative",overflow:"hidden",background:C.bg}}>
        <div style={{position:"absolute",inset:0,backgroundImage:`linear-gradient(${C.orange}06 1px,transparent 1px),linear-gradient(90deg,${C.orange}06 1px,transparent 1px)`,backgroundSize:"60px 60px"}}/><Orb top="-10%" right="-5%" size={500}/><Orb bottom="-20%" left="30%" size={400} color={C.pink} opacity={0.07} delay="3s"/>
        <div style={{position:"relative",zIndex:2,maxWidth:"1100px",margin:"0 auto",width:"100%",textAlign:"center"}}>
          <div style={{animation:"fadeUp .5s ease forwards",opacity:0,marginBottom:"18px"}}><Tag>Pricing</Tag></div>
          <h1 style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"clamp(44px,8vw,92px)",lineHeight:.93,color:C.white,animation:"fadeUp .55s .08s ease forwards",opacity:0,marginBottom:"18px"}}>Simple pricing.<br/><span style={{color:C.orange}}>Real value.</span></h1>
          <p style={{fontFamily:"'DM Sans',sans-serif",fontSize:"clamp(14px,1.8vw,18px)",color:C.dim,maxWidth:"480px",lineHeight:1.75,animation:"fadeUp .55s .16s ease forwards",opacity:0,margin:"0 auto"}}>Start free. Scale when you're ready. No lock-ins, no hidden fees.</p>
        </div>
      </section>
      <Divider/>
      <section className="sec-pad" style={{background:C.bg2}}>
        <div style={{maxWidth:"1100px",margin:"0 auto"}}>
          {/* Product Selector */}
          <div style={{display:"flex",justifyContent:"center",gap:"8px",marginBottom:"32px",flexWrap:"wrap"}}>
            {Object.entries(products).map(([k,v])=><button key={k} onClick={()=>setActiveProduct(k)} style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"14px",letterSpacing:"2px",padding:"12px 28px",background:activeProduct===k?v.color:"transparent",color:activeProduct===k?C.bg:C.dim,border:`1px solid ${activeProduct===k?v.color:"rgba(255,255,255,0.12)"}`,borderRadius:"2px",cursor:"pointer",transition:"all .2s",display:"flex",alignItems:"center",gap:"8px"}}>{v.icon} {k}</button>)}
          </div>
          {/* Annual Toggle */}
          <div style={{display:"flex",justifyContent:"center",marginBottom:"44px"}}>
            <div style={{display:"inline-flex",background:"rgba(255,255,255,0.04)",border:"1px solid rgba(255,255,255,0.1)",borderRadius:"3px",padding:"4px"}}>
              {["Monthly","Annual"].map(t=><button key={t} onClick={()=>setAnnual(t==="Annual")} style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"13px",letterSpacing:"2px",padding:"8px 22px",background:(t==="Annual")===annual?C.orange:"transparent",color:(t==="Annual")===annual?C.bg:C.dim,border:"none",borderRadius:"2px",cursor:"pointer",transition:"all .2s"}}>{t}{t==="Annual"&&<span style={{fontSize:"10px",marginLeft:"6px",opacity:.8}}>-20%</span>}</button>)}
            </div>
          </div>
          <p style={{fontFamily:"'DM Sans',sans-serif",fontSize:"14px",color:C.dim,textAlign:"center",marginBottom:"36px"}}>{current.tagline}</p>
          <div className="grid-3">{current.tiers.map((t,i)=><PricingCard key={i} {...t} annual={annual} color={current.color} onCta={()=>openWaitlist(`${activeProduct} ${t.plan}`)}/>)}</div>
          <Reveal><p style={{fontFamily:"'DM Sans',sans-serif",fontSize:"12px",color:C.dimmer,textAlign:"center",marginTop:"24px"}}>All paid plans include a 14-day free trial. No credit card required for free tiers.</p></Reveal>
        </div>
      </section>
      <Divider/>
      {/* Comparison Note */}
      <section className="sec-pad-sm">
        <div style={{maxWidth:"900px",margin:"0 auto",textAlign:"center"}}>
          <Reveal><Tag>All plans include</Tag><div style={{display:"flex",gap:"12px",flexWrap:"wrap",justifyContent:"center",marginTop:"24px"}}>
            {["City map presence","Community access","In-app support","VibeCircle app (iOS + Android)","99.9% uptime SLA","POPIA compliance","SSL & data encryption"].map(f=><div key={f} style={{display:"flex",gap:"7px",alignItems:"center",padding:"10px 18px",background:"rgba(255,107,0,0.04)",border:`1px solid ${C.border}`,borderRadius:"2px"}}><span style={{color:C.orange,fontSize:"12px"}}>---</span><span style={{fontFamily:"'DM Sans',sans-serif",fontSize:"13px",color:"rgba(255,255,255,0.75)"}}>{f}</span></div>)}
          </div></Reveal>
        </div>
      </section>
      <Divider/>
      <section className="sec-pad" style={{background:C.bg2}}><div style={{maxWidth:"800px",margin:"0 auto"}}><Reveal style={{marginBottom:"44px"}}><Tag>Pricing FAQ</Tag><h2 style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"clamp(26px,4vw,44px)",color:C.white,lineHeight:1,marginTop:"16px"}}>Questions about <span style={{color:C.orange}}>pricing.</span></h2></Reveal><FAQ items={faqItems}/></div></section>
    </div>
  );
}
