          <Reveal>
            <Tag>Founder's Story</Tag>
            <h2 style={{ fontFamily: "'Bebas Neue',sans-serif", fontSize: "clamp(30px,5vw,56px)", color: C.white, lineHeight: 1, margin: "16px 0 36px" }}>
              What if maps
              <br />
              <span style={{ color: C.orange }}>were alive?</span>
            </h2>
          </Reveal>
